// gen_items_c — 6 NEW auto-used consumables filling mechanical niches the core
// and earlier gen packs don't cover (lifesteal surge, defensive ward, escape
// mobility, multishot/pierce surge, a thrown toxic cloud, and a coin cache).
// File-body form (no import/export); all bindings come from the header above.
// Item schema: { id,name,desc,tier,weight,price,icon:'item_<id>',
//   use(world,player,run) -> truthy if consumed }.
// Numbers kept modest — the game was recently nerfed.

// ===========================================================================
// ITEMS (6)
// ===========================================================================

// 1) 嗜血藥劑 — VAMPIRIC SURGE. Temporary lifesteal + a trickle of regen so
//    aggressive play heals you back. Distinct from flat heal potions.
Items.register({
  id: 'ic_bloodthirst_vial', name: '嗜血藥劑', desc: '8 秒內 生命吸取 +8%、每秒回復 +3', tier: 2, weight: 6, price: 34, icon: 'item_ic_bloodthirst_vial',
  use: (w, p) => {
    p.addTimedBuff(8,
      (pl) => { pl.stats.lifesteal += 0.08; pl.stats.hpRegen += 3; },
      (pl) => { pl.stats.lifesteal -= 0.08; pl.stats.hpRegen -= 3; },
      P.red);
    w.particles.ring(p.x, p.y, P.red, 16, 90);
    w.particles.text(p.x, p.y - 16, '嗜血！', { color: P.redL, size: 13 });
    return true;
  },
});

// 2) 鐵衛護膏 — WARDING SALVE. A defensive layer (armor + flat defense) that
//    soaks hits without granting full immunity, so it complements shields.
Items.register({
  id: 'ic_warding_salve', name: '鐵衛護膏', desc: '8 秒內 減傷 +22%、防禦 +8', tier: 2, weight: 5, price: 36, icon: 'item_ic_warding_salve',
  use: (w, p) => {
    p.addTimedBuff(8,
      (pl) => { pl.stats.armorMult += 0.22; pl.stats.defense += 8; },
      (pl) => { pl.stats.armorMult -= 0.22; pl.stats.defense -= 8; },
      P.steel);
    w.particles.ring(p.x, p.y, P.steelL, 16, 85);
    w.particles.text(p.x, p.y - 16, '護膏', { color: P.steelL, size: 13 });
    return true;
  },
});

// 3) 疾影靈藥 — QUICKSILVER ESCAPE. Big move-speed + dodge for kiting out of a
//    bad surround. No combat power, so it's a pure mobility tool.
Items.register({
  id: 'ic_quicksilver_tonic', name: '疾影靈藥', desc: '7 秒內 移動速度 +28%、閃避 +15%', tier: 1, weight: 7, price: 24, icon: 'item_ic_quicksilver_tonic',
  use: (w, p) => {
    p.addTimedBuff(7,
      (pl) => { pl.stats.speed *= 1.28; pl.stats.dodge += 0.15; },
      (pl) => { pl.stats.speed /= 1.28; pl.stats.dodge -= 0.15; },
      P.toxic);
    w.particles.ring(p.x, p.y, P.toxic, 18, 110);
    w.particles.text(p.x, p.y - 16, '疾影！', { color: P.green, size: 13 });
    return true;
  },
});

// 4) 裂片彈藥 — SPLINTER ROUNDS. +1 projectile and +1 pierce for a window —
//    a build-shaping offense surge that's different from raw damage/fire-rate.
Items.register({
  id: 'ic_splinter_rounds', name: '裂片彈藥', desc: '8 秒內 投射物 +1、穿透 +1', tier: 2, weight: 6, price: 38, icon: 'item_ic_splinter_rounds',
  use: (w, p) => {
    p.addTimedBuff(8,
      (pl) => { pl.stats.projCountAdd += 1; pl.stats.pierceAdd += 1; },
      (pl) => { pl.stats.projCountAdd -= 1; pl.stats.pierceAdd -= 1; },
      P.shardL);
    w.particles.ring(p.x, p.y, P.shardL, 16, 95);
    w.particles.text(p.x, p.y - 16, '裂片！', { color: P.shardL, size: 13 });
    return true;
  },
});

// 5) 劇毒燒瓶 — TOXIC FLASK. Splash a poison cloud at your feet: light up-front
//    hit plus a guaranteed poison DoT on everything caught. Modest direct dmg.
Items.register({
  id: 'ic_toxic_flask', name: '劇毒燒瓶', desc: '砸出毒霧，對周圍敵人造成 28 點傷害並施加中毒', tier: 1, weight: 7, price: 26, icon: 'item_ic_toxic_flask',
  use: (w, p) => {
    fillCircleWorld(p.x, p.y, 84, withAlpha(P.poisonD, 0.16));
    w.particles.ring(p.x, p.y, P.poison, 20, 150);
    w.particles.burst(p.x, p.y, 12, { color: [P.poison, P.toxic], speed: 90, size: 2.2, life: 0.5, glow: true });
    w.dealAreaDamage(p.x, p.y, 84, 28, { knockback: 20, status: { type: 'poison', chance: 1 } });
    w.particles.text(p.x, p.y - 16, '毒！', { color: P.toxic, size: 13 });
    return true;
  },
});

// 6) 賞金錢袋 — COIN CACHE. Pure economy: bank a little gold now and scatter a
//    couple of soul-shards to grab. Always consumed.
Items.register({
  id: 'ic_coin_cache', name: '賞金錢袋', desc: '立即獲得 30 金幣，並在腳邊灑出 3 顆魂晶', tier: 1, weight: 6, price: 18, icon: 'item_ic_coin_cache',
  use: (w, p, run) => {
    run.gold += 30;
    run.goldEarned += 30;
    for (let i = 0; i < 3; i++) {
      const a = Math.random() * TAU, off = 8 + Math.random() * 12;
      w.addPickup('shard', p.x + Math.cos(a) * off, p.y + Math.sin(a) * off, 1);
    }
    w.particles.ring(p.x, p.y, P.goldL, 16, 100);
    w.particles.text(p.x, p.y - 16, '金幣 +30', { color: P.goldL, size: 13 });
    Sfx.play('coin');
    return true;
  },
});

// ===========================================================================
// ICONS (16x16 panel; outline() called last via defineIcon convention)
// ===========================================================================

// reusable flask body (matches core content-icon style)
function icFlask(p, liquid) {
  p.rect(6, 2, 4, 2, P.gray4);     // cork
  p.rect(5, 3, 6, 1, P.gray3);     // neck rim
  p.ellipse(8, 9, 3.4, 4.4, darken(liquid, 0.28));
  p.ellipse(8, 9, 2.6, 3.4, liquid);
  p.px(6, 7, lighten(liquid, 0.4));                       // glint
  p.ellipse(8, 5.5, 2.2, 1, lighten(liquid, 0.2));        // surface
}

// 1) bloodthirst — red flask with a fang
defineIcon('item_ic_bloodthirst_vial', P.blood, (p) => {
  icFlask(p, P.red);
  p.px(7, 6, P.white); p.line(7, 6, 7, 9, P.white); // fang
  p.px(9, 6, P.redL);
});

// 2) warding salve — steel shield crest over a jar
defineIcon('item_ic_warding_salve', P.steelD, (p) => {
  for (let y = 3; y <= 12; y++) {
    const t = (y - 3) / 9;
    const wd = 4.2 * (1 - t * 0.55) * (y > 9 ? (13 - y) / 3.5 : 1);
    p.hline(8 - wd, 7 + wd, y, t < 0.45 ? P.steel : darken(P.steel, 0.18));
  }
  p.hline(5, 10, 3, P.steelL);
  p.vline(4, 9, 8, lighten(P.steel, 0.2));
  p.line(6, 6, 8, 9, P.iceD); p.line(10, 6, 8, 9, P.iceD); // chevron
});

// 3) quicksilver — green flask with speed lines
defineIcon('item_ic_quicksilver_tonic', P.greenD, (p) => {
  icFlask(p, P.toxic);
  p.hline(1, 4, 5, P.green); p.hline(1, 5, 8, P.toxic); p.hline(1, 4, 11, P.green); // trail
});

// 4) splinter rounds — a clutch of crystalline darts fanning out
defineIcon('item_ic_splinter_rounds', P.shardD, (p) => {
  p.line(3, 13, 8, 4, P.shard);
  p.line(8, 13, 8, 3, P.shardL);
  p.line(13, 13, 8, 4, P.shard);
  p.px(8, 3, P.white); p.px(3, 13, P.shardL); p.px(13, 13, P.shardL);
  p.px(6, 8, lighten(P.shardL, 0.2)); p.px(10, 8, lighten(P.shardL, 0.2));
});

// 5) toxic flask — bulbous poison bottle with a vapour wisp
defineIcon('item_ic_toxic_flask', P.poisonD, (p) => {
  p.rect(7, 2, 2, 2, P.gray4);                 // cork
  p.ellipse(8, 10, 4, 4, darken(P.poison, 0.3));
  p.ellipse(8, 10, 3, 3, P.poison);
  p.px(6, 8, P.toxic); p.px(9, 11, P.toxic);   // bubbles
  p.line(8, 5, 7, 2, P.toxic); p.line(8, 5, 9, 1, P.toxic); // vapour
});

// 6) coin cache — a leather pouch bulging with a gold coin
defineIcon('item_ic_coin_cache', P.woodD, (p) => {
  p.ellipse(8, 10, 5, 4, P.leather);
  p.ellipse(8, 10, 4, 3, darken(P.leather, 0.18));
  p.rect(6, 4, 4, 2, darken(P.leather, 0.3));  // cinched neck
  p.hline(6, 9, 5, P.woodL);
  p.ellipse(8, 10, 2, 2, P.gold); p.px(8, 10, P.goldL); // coin
  p.px(7, 9, P.white);
});

